import anime from"../anime.min.js";function sleep(ms){return new Promise(resolve=>setTimeout(resolve,ms))}function clamp(value,min,max){return Math.min(Math.max(value,min),max)}function downloadFile(filename){var e=document.createElement("a");e.href=filename,e.download=filename.slice(filename.lastIndexOf("/")+1),document.body.appendChild(e),e.click(),e.remove()}function downloadString(text,filename){var e=new Blob([text],{type:"text/plain"}),e=URL.createObjectURL(e),t=document.createElement("a");t.href=e,t.download=filename,t.click(),URL.revokeObjectURL(e)}async function asyncFetch(url){return await(await fetch(url)).text()}async function animate(update,duration,easing="easeOutQuad"){if(0===duration)update(1);else{const e={t:0};await anime({targets:e,t:1,duration:duration,easing:easing,update:()=>update(e.t),complete:()=>update(1)}).finished}}function fuzzySearch(query,names,threshold=.3){var e=[],t=query.toLowerCase();for(const r of names){var a=calculateSimilarity(t,r.toLowerCase());threshold<=a&&e.push({name:r,score:a})}return e.sort((a,b)=>b.score-a.score).map(result=>result.name)}function calculateSimilarity(query,target){if(query===target)return 1;if(0===query.length||0===target.length)return 0;if(target.startsWith(query))return.95+query.length/target.length*.05;var e;for(const r of target.split(" "))if(r.startsWith(query))return.85+query.length/r.length*.1;if(target.includes(query))return.6+query.length/target.length*.2;let t=0,a=0;for(let n=0;n<target.length&&a<query.length;n++)target[n]===query[a]&&(e=1-n/target.length*.8,t+=e,a++);return Math.min(t/query.length,.5)}function searchProperties(obj,regex,seen=new WeakSet,path=""){var e=[];if(null!==obj&&"object"==typeof obj&&!seen.has(obj)){seen.add(obj);for(const a of Object.keys(obj)){var t=path?path+"."+a:a;regex.test(a)&&e.push({path:t,key:a,value:obj[a]}),null!==obj[a]&&"object"==typeof obj[a]&&e.push(...searchProperties(obj[a],regex,seen,t))}}return e}export{sleep,clamp,downloadFile,downloadString,asyncFetch,animate,fuzzySearch,searchProperties};